.card-hover {
      position: relative;
      width: 300px;
      height: 450px;
      border-radius: 15px;
      overflow: hidden;
      box-shadow: 0 8px 16px rgba(0,0,0,0.3);
      cursor: pointer;
    }

    .card-hover img {
      width: 100%;
      height: 100%;
      object-fit: cover;
      transition: transform 0.5s ease;
    }

    .card-hover:hover img {
      transform: scale(1.1);
    }

    .overlay {
      position: absolute;
      top: 0;
      left: 0;
      width: 100%;
      height: 100%;
      background: rgba(0,0,0,0.6);
      color: white;
      opacity: 0;
      transition: opacity 0.5s ease;
      display: flex;
      flex-direction: column;
      justify-content: center;
      align-items: center;
      padding: 20px;
      text-align: center;
    }

    .card-hover:hover .overlay {
      opacity: 1;
    }

    .overlay h2 {
      font-size: 28px;
      font-weight: bold;
    }

    .overlay p {
      font-size: 15px;
      margin: 15px 0;
    }

    .btn-custom {
      background-color: #dfe6e9;
      color: black;
      border: none;
      padding: 10px 20px;
      border-radius: 8px;
      font-weight: 500;
      transition: background 0.3s;
    }

    .btn-custom:hover {
      background-color: #b2bec3;
    }
    /*
 *  Bootstrap Carousel Effect Ken Burns
 * ===========================================================================*/

@keyframes kenburns {
  0% {
    transform: scale(1);
    transition: transform 20000ms linear 0s;
  }

  100% {
    transform: scale(1.4);
    transition: transform 20000ms linear 0s;
  }
}

/* Carousel Wrapper */
.kb-carousel {
  overflow: hidden;
  max-height: 650px;
}

/* Carousel Items */
.kb-carousel .carousel-item {
  transition: transform .6s ease-in-out 0s, opacity ease-in-out .6s;
}

.kb-carousel .carousel-item.active {
  transition: transform .6s ease-in-out 0s, opacity ease-in-out .6s;
}

.kb-carousel > .carousel-inner > .carousel-item > img,
.kb-carousel > .carousel-inner > .carousel-item > a > img {
  opacity: 0.8;
  animation: kenburns 20000ms linear 0s infinite alternate;
}

.kb-carousel .carousel-item-next.carousel-item-start .carousel-caption,
.kb-carousel .carousel-item-prev.carousel-item-end .carousel-caption {
  z-index: 0;
  opacity: 0;
}

/* Carousel Captions */
.kb-caption {
  right: 0%;
  left: 7%;
  bottom: 25%;
  padding: 0;
  width: 80%;
}

.kb-caption-left {
  margin-right: auto;
}

.kb-caption-right {
  margin-left: auto;
}

.kb-caption-center {
  margin: auto;
}

.kb-caption h1,
.kb-caption h3 {
  padding: 0.5rem 0;
  margin-bottom: 0;
}

.kb-caption h1 {
    font-weight:900;
  animation-delay: 1s;
  color: #fff;
  background: rgba(0 0 0 / 0.5);
  
}

.kb-caption h3 {
  animation-delay: 1.5s;
  color: #fff;
  font-size:16px;
  background: rgba(0 0 0 / 0.5);
}

@media (min-width: 768px) {
  .kb-caption {
    bottom: 37%;
    width: 100%;
  }
  
}

@media only screen and (max-width: 600px) {
  .carousel-caption.kb-caption.kb-caption-right{
      display:none;
      position: relative;
    left: 0;
    width: 100%;
  }
  .booking_left_img{
      display:none;
  }
  .home_section .home.home-long .home-content.mix-layout{
          margin-top: 0px !important;
  }
  .right_info{
    width:50%;   
  }
  .left_info{
    width:50%;   
  }
}
@media (min-width: 1200px) {
  .kb-caption {
    bottom: 36%;
  }
}

/* Controls */
.kb-control-prev,
.kb-control-next {
  width: 3.5rem;
  height: 3.5rem;
  margin: auto 0;
  opacity: 0;
  color: #fff;
  background: rgba(0 0 0 / 0.7);
}

.kb-carousel:hover .kb-control-prev,
.kb-carousel:hover .kb-control-next {
  opacity: 1;
}

.kb-control-prev {
  left: 1%;
}

.kb-control-next {
  right: 1%;
}

.kb-control-prev:hover,
.kb-control-prev:focus,
.kb-control-next:hover,
.kb-control-next:focus {
  color: #fff;
  background: rgba(0 0 0 / 1);
}

/* Support for dark mode */
[data-bs-theme = "dark"] .carousel .carousel-control-next-icon,
[data-bs-theme = "dark"] .carousel .carousel-control-prev-icon {
  filter: none;
}


